package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.artikelmotor.BoekJaarArtikelKey;
import be.schaubroeck.lpb.rkm.rekenmotor.BelastbaarFiscaalJaarAchterstalKey;
import be.schaubroeck.lpb.rkm.rekenmotor.BelastbaarFiscaalJaarKey;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenHoofdArtikelKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenHoofdKey;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.ArtikelBedrag;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enumtypes.AardRekenelement;
import be.schaubroeck.lpb.tools.enumtypes.BoekingType;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.util.AlgemeenTools;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.HashMultimap;
import com.google.common.collect.Multimap;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Value;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class ArtikelLoonElementManagerFactoryImp implements ArtikelLoonElementManagerFactory {

    @Autowired
    private AardKodeExtensieFacade aardKodeExtensieFacade;

    @Override
    public ArtikelLoonElementManager create(Persoon persoon, Set<Opdracht> opdrachten, List<RekenHoofd> rekenResultaten) {
        ArtikelLoonElementManager manager = new ArtikelLoonElementManagerImp();
        verwerkRekenResultatenTotArtikelLoonElementen(opdrachten, rekenResultaten, manager);
        toevoegenDummyRekenHoofdArtikelKeyVoorCaseEnkelRekenOverdrachten(rekenResultaten, manager);
        return manager;
    }

    private void verwerkRekenResultatenTotArtikelLoonElementen(Set<Opdracht> opdrachten, List<RekenHoofd> rekenResultaten, ArtikelLoonElementManager manager) {
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(opdrachten);
        Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap = new HashMap<>();
        for (RekenHoofd hoofd : rekenResultaten) {
            Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                RekenLijnInfo rekenLijnInfo = createRekenLijnInfo(lijn, opdracht, akeIdToAardKodeExtensieMap);
                for (BoekJaarArtikelKey boekJaarArtikelKey : rekenLijnInfo.getArtikelBedragMap().keySet()) {
                    LoonElement element = getOrCreateLoonElement(rekenLijnInfo, boekJaarArtikelKey, manager);
                    verwerkArtikelBedragen(element, boekJaarArtikelKey, rekenLijnInfo);
                }
            }
        }
    }

    private void toevoegenDummyRekenHoofdArtikelKeyVoorCaseEnkelRekenOverdrachten(List<RekenHoofd> rekenResultaten, ArtikelLoonElementManager manager) {
        for (RekenHoofd hoofd : rekenResultaten) {
            if (heeftEnkelRekenOverdrachten(hoofd)) {
                RekenHoofdArtikelKey closestKey = findClosest(hoofd, manager.getRekenHoofdArtikelKeys());
                if (closestKey != null) {
                    manager.addExtraRekenHoofdArtikelKey(createDummy(hoofd, closestKey));
                }
            }
        }
    }

    private boolean heeftEnkelRekenOverdrachten(RekenHoofd hoofd) {
        return hoofd.getRekenLijnen().isEmpty() && !hoofd.getRekenOverdrachten().isEmpty();
    }

    private RekenHoofdArtikelKey findClosest(RekenHoofd hoofd, Set<RekenHoofdArtikelKey> rekenHoofdArtikelKeys) {
        return rekenHoofdArtikelKeys.stream()
                .filter(x -> match(hoofd, x))
                .max(Comparator.comparing(RekenHoofdArtikelKey::getRekenTijdstip).thenComparing(RekenHoofdArtikelKey::compareTo))
                .orElse(null);
    }

    private boolean match(RekenHoofd hoofd, RekenHoofdArtikelKey key) {
        return key.getRekenHoofdKey().equals(new RekenHoofdKey(hoofd)) && key.getBeginDatum().equals(hoofd.getBeginDatum()) &&
                key.getRekenTijdstip().isBefore(hoofd.getRekenTijdstip());
    }

    private RekenHoofdArtikelKey createDummy(RekenHoofd hoofd, RekenHoofdArtikelKey key) {
        return new RekenHoofdArtikelKey(hoofd, key.getBoekJaar(), key.getKostenplaats(), key.getArtikel(), hoofd.getRekenTijdstip());
    }

    private Opper bepaalOpper(RekenLijn lijn, Opdracht opdracht) {
        Opper opper = RekenTools.findOpper(opdracht, lijn.getEindDatum());
        if (opper == null) {
            opper = RekenTools.getOpperLaatsteGegevens(opdracht);
        }
        return opper;
    }

    private AardKodeExtensie bepaalAardKodeExtensie(RekenLijn lijn, Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap) {
        AardKodeExtensie looncode = akeIdToAardKodeExtensieMap.get(lijn.getAardKodeExtensie().getId());
        if (looncode == null) {
            looncode = aardKodeExtensieFacade.getById(lijn.getAardKodeExtensie().getId());
            akeIdToAardKodeExtensieMap.put(looncode.getId(), looncode);
        }
        return looncode;
    }

    private LnedefRegBv bepaalRegime(RekenLijn lijn, AardKodeExtensie looncode) {
        LnedefRegBv regime = looncode.getRegimeBv();
        if (isAfwijkendRegime(lijn, looncode)) {
            regime = lijn.getRegimeBv();
        }
        return regime;
    }

    private boolean isAfwijkendRegime(RekenLijn lijn, AardKodeExtensie looncode) {
        return lijn.getRegimeBv() != looncode.getRegimeBv() && !checkEnkelRekenBedragenMetAfwijkendRegime(lijn.getRekenBedragen());
    }

    private RekenLijnInfo createRekenLijnInfo(RekenLijn lijn, Opdracht opdracht, Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap) {
        AardKodeExtensie looncode = bepaalAardKodeExtensie(lijn, akeIdToAardKodeExtensieMap);
        return RekenLijnInfo.builder()
                .rekenHoofd(lijn.getRekenHoofd())
                .rekenLijnPeriode(new LocalDateInterval(lijn.getBeginDatum(), lijn.getEindDatum()))
                .referentieJaar(lijn.getReferentieJaar())
                .opper(bepaalOpper(lijn, opdracht))
                .looncode(looncode)
                .artikelBedragMap(createArtikelBedragMap(lijn))
                .regime(bepaalRegime(lijn, looncode))
                .lijnRegime(lijn.getRegimeBv())
                .isAfwijkendRegime(isAfwijkendRegime(lijn, looncode))
                .build();
    }


    private Multimap<BoekJaarArtikelKey, ArtikelBedrag> createArtikelBedragMap(RekenLijn lijn) {
        Multimap<BoekJaarArtikelKey, ArtikelBedrag> artikelBedragMap = HashMultimap.create();
        for (RekenBedrag bedrag : lijn.getRekenBedragen()) {
            for (ArtikelBedrag artikelBedrag : bedrag.getArtikelBedragen()) {
                AardRekenelement typeBoeking = artikelBedrag.getBoekingType() == BoekingType.TEGENBOEKING ? AardRekenelement.TEGENBOEKING : lijn.getTypeBoeking();
                BoekJaarArtikelKey key =
                        new BoekJaarArtikelKey(artikelBedrag.getArtikelHoofd().getBoekJaar(), artikelBedrag.getKostenplaats(), artikelBedrag.getArtikel(), typeBoeking,
                                artikelBedrag.getArtikelHoofd().getArtikelTijdstip());
                artikelBedragMap.put(key, artikelBedrag);
            }
        }
        return artikelBedragMap;
    }

    private LoonElement getOrCreateLoonElement(RekenLijnInfo rekenLijnInfo, BoekJaarArtikelKey boekJaarArtikelKey, ArtikelLoonElementManager manager) {
        RekenHoofdArtikelKey rekenHoofdArtikelKey =
                new RekenHoofdArtikelKey(rekenLijnInfo.getRekenHoofd(), boekJaarArtikelKey.getBoekJaar(), boekJaarArtikelKey.getKostenplaats(),
                        boekJaarArtikelKey.getArtikel(),
                        boekJaarArtikelKey.getArtikelTijdstip());
        LoonElement element =
                manager.getLoonElement(rekenLijnInfo.getLooncode(), rekenLijnInfo.getOpper(), rekenHoofdArtikelKey, rekenLijnInfo.getRekenLijnPeriode(),
                        boekJaarArtikelKey.getTypeBoeking(),
                        rekenLijnInfo.getReferentieJaar(), rekenLijnInfo.getRegime());
        if (element == null) {
            element = new LoonElement(rekenLijnInfo.getLooncode());
            element.setReferentieJaar(rekenLijnInfo.getReferentieJaar());
            element.putProperty(RekenChainKey.REKENLIJN_PERIODE_KEY, rekenLijnInfo.getRekenLijnPeriode());
            element.putProperty(RekenChainKey.REKENLIJN_TYPE_BOEKING_KEY, boekJaarArtikelKey.getTypeBoeking());

            if (rekenLijnInfo.isAfwijkendRegime()) {
                element.putProperty(RekenChainKey.AFWIJKEND_REGIME_KEY, rekenLijnInfo.getRegime());
            }
            manager.addLoonElement(element, rekenLijnInfo.getOpper(), rekenHoofdArtikelKey);
        }
        return element;
    }

    private void verwerkArtikelBedragen(LoonElement element, BoekJaarArtikelKey boekJaarArtikelKey, RekenLijnInfo rekenLijnInfo) {
        RekenHoofd hoofd = rekenLijnInfo.getRekenHoofd();
        for (ArtikelBedrag artikelBedrag : rekenLijnInfo.getArtikelBedragMap().get(boekJaarArtikelKey)) {
            RekenBedragType bedragType = artikelBedrag.getRekenBedrag().getBedragType();
            if (bedragType == RekenBedragType.BELASTBAAR || bedragType == RekenBedragType.RUW_BELASTBAAR ||
                    bedragType == RekenBedragType.VRIJSTELLING_BELASTBAAR) {
                MoneyKey moneyKey = RekenTools.bedragTypeToMoneyKey(bedragType);
                element.addToProperty(new BelastbaarFiscaalJaarKey(hoofd.getFiscaalJaar(), moneyKey), artikelBedrag.getBedrag());
                element.addToProperty(new BelastbaarFiscaalJaarAchterstalKey(hoofd.getFiscaalJaar(), moneyKey, hoofd.getAchterstal()),
                        artikelBedrag.getBedrag());
                element.addToProperty(new BelastbaarFiscaalJaarAchterstalKey(null, moneyKey, hoofd.getAchterstal()), artikelBedrag.getBedrag());
            }
            element.addToProperty(RekenTools.bedragTypeToMoneyKey(artikelBedrag.getRekenBedrag().getBedragType(), rekenLijnInfo.getLijnRegime(), hoofd.getBeginDatum()),
                    artikelBedrag.getBedrag());
        }
    }

    @Value
    @AllArgsConstructor
    @Builder
    private static class RekenLijnInfo {
        RekenHoofd rekenHoofd;
        LocalDateInterval rekenLijnPeriode;
        Integer referentieJaar;
        Opper opper;
        AardKodeExtensie looncode;
        Multimap<BoekJaarArtikelKey, ArtikelBedrag> artikelBedragMap;
        LnedefRegBv regime;
        LnedefRegBv lijnRegime;
        boolean isAfwijkendRegime;


    }

    private boolean checkEnkelRekenBedragenMetAfwijkendRegime(Set<RekenBedrag> rekenBedragen) {
        boolean checked = true;
        for (RekenBedrag rekenBedrag : rekenBedragen) {
            checked = checked && rekenBedrag.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN;
        }
        return checked;
    }

}
